const data = $input.first().json || {};
const txnId = data.query?.txnId || data.txnId;

if (!txnId) {
  throw new Error("txnId is required in query params");
}

return [{ txnId }];

// 1. Helper to recursively clean and format text in any object/string
const deepFormat = (data) => {
  if (typeof data === 'string') {
    return data
      .replace(/\\n/g, '\n')       // Convert literal \n to real newlines
      .replace(/\n{3,}/g, '\n\n')  // Standardize spacing (max 2 newlines)
      .trim();
  }

  if (data !== null && typeof data === 'object') {
    const cleaned = Array.isArray(data) ? [] : {};
    for (const key in data) {
      cleaned[key] = deepFormat(data[key]);
    }
    return cleaned;
  }

  return data;
};

// 2. Safely extract AI Analysis
let aiAnalysisRaw = $json.output || "";
let aiParsed = {};

try {
  // If it's already an object, use it; if string, parse it.
  aiParsed = (typeof aiAnalysisRaw === "string") ? JSON.parse(aiAnalysisRaw) : aiAnalysisRaw;
} catch (e) {
  aiParsed = { raw: aiAnalysisRaw };
}

// 3. Construct the perfectly formatted final object
return [{
  // Transaction Metadata
  txnId: $json.txnId,
  respCode: $json.respCode,

  // Formatted System Messages
  processorMessage: deepFormat($json.addtlRespData || "N/A"),

  // Rule Engine Details (Safe Navigation)
  ruleDetails: {
    message: $json.ruleResult?.message || "No rules triggered",
    reason: deepFormat($json.ruleResult?.reason || ""),
    fixSuggestion: deepFormat($json.ruleResult?.fix || "No action required")
  },

  // AI Deep Analysis (Cleaned up)
  aiAnalysis: deepFormat(aiParsed),

  // This is the main field your HTML dashboard uses
  prettyOutput: deepFormat(typeof aiAnalysisRaw === "string" ? aiAnalysisRaw : JSON.stringify(aiAnalysisRaw, null, 2))
}];

